#!/usr/bin/env node
/**
 * generate-tokens.js
 *
 * Reads the compiled token files from dist/src/theme/tokens and
 * dist/src/theme/semantic-tokens, then writes dist/tokens.css containing
 * all design tokens as CSS custom properties under the --osmos-* namespace.
 *
 * Output structure:
 *   :root, [data-theme="light"]  — base tokens + light semantic tokens
 *   [data-theme="dark"]          — dark semantic tokens
 */

const fs = require("fs");
const path = require("path");

const DIST = path.resolve(__dirname, "../dist/src/theme");
const OUT = path.resolve(__dirname, "../dist/tokens.css");

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** Convert a token path array to a CSS variable name: --osmos-colors-blue-500 */
function toCSSVar(parts) {
  return "--osmos-" + parts.map((p) => p.replace(/\./g, "-")).join("-");
}

/**
 * Resolve a Chakra token reference like "{colors.gray.100}"
 * to a CSS var() call: var(--osmos-colors-gray-100)
 */
function resolveRef(value) {
  if (typeof value !== "string") return value;
  return value.replace(/\{([^}]+)\}/g, (_, ref) => {
    const varName = "--osmos-" + ref.replace(/\./g, "-");
    return `var(${varName})`;
  });
}

/**
 * Recursively walk a token object and collect flat entries.
 * Each entry is { path: string[], value: string }.
 * Stops recursing when it finds a node with a "value" key.
 */
function flattenTokens(obj, path = []) {
  const entries = [];
  for (const [key, val] of Object.entries(obj)) {
    if (val && typeof val === "object" && "value" in val) {
      entries.push({ path: [...path, key], value: val.value });
    } else if (val && typeof val === "object") {
      entries.push(...flattenTokens(val, [...path, key]));
    }
  }
  return entries;
}

// ---------------------------------------------------------------------------
// Load tokens
// ---------------------------------------------------------------------------

let tokens, semanticTokens;
try {
  ({ tokens } = require(path.join(DIST, "tokens")));
  ({ semanticTokens } = require(path.join(DIST, "semantic-tokens")));
} catch (e) {
  console.error("Error loading compiled tokens. Run build:babel-only first.");
  console.error(e.message);
  process.exit(1);
}

// ---------------------------------------------------------------------------
// 1. Base tokens  →  :root
// ---------------------------------------------------------------------------

const baseLines = [];
for (const [category, tokenGroup] of Object.entries(tokens)) {
  baseLines.push(`  /* ${category} */`);
  const entries = flattenTokens(tokenGroup, [category]);
  for (const { path, value } of entries) {
    const cssVar = toCSSVar(path);
    const resolvedValue = resolveRef(value);
    baseLines.push(`  ${cssVar}: ${resolvedValue};`);
  }
  baseLines.push("");
}

// ---------------------------------------------------------------------------
// 2. Semantic tokens  →  split by _light / _dark
// ---------------------------------------------------------------------------

const lightLines = [];
const darkLines = [];

function flattenSemantic(obj, path = []) {
  for (const [key, val] of Object.entries(obj)) {
    if (val && typeof val === "object" && "value" in val) {
      const cssVar = toCSSVar(path.length ? [...path, key] : [key]);
      const v = val.value;
      if (v && typeof v === "object" && ("_light" in v || "_dark" in v)) {
        if (v._light !== undefined) {
          lightLines.push(`  ${cssVar}: ${resolveRef(v._light)};`);
        }
        if (v._dark !== undefined) {
          darkLines.push(`  ${cssVar}: ${resolveRef(v._dark)};`);
        }
      } else {
        // No light/dark split — add to both
        const resolved = resolveRef(typeof v === "string" ? v : String(v));
        lightLines.push(`  ${cssVar}: ${resolved};`);
        darkLines.push(`  ${cssVar}: ${resolved};`);
      }
    } else if (val && typeof val === "object") {
      flattenSemantic(val, path.length ? [...path, key] : [key]);
    }
  }
}

for (const [category, group] of Object.entries(semanticTokens)) {
  lightLines.push(`  /* ${category} */`);
  darkLines.push(`  /* ${category} */`);
  flattenSemantic(group, [category]);
  lightLines.push("");
  darkLines.push("");
}

// ---------------------------------------------------------------------------
// 3. Write CSS file
// ---------------------------------------------------------------------------

const css = `/*
 * @onlinesales-ai/ui — Design Tokens
 * Auto-generated by scripts/generate-tokens.js
 * Do not edit manually.
 *
 * Usage:
 *   import "@onlinesales-ai/ui/tokens.css";
 *
 * Variables are prefixed with --osmos-
 * Semantic tokens respond to [data-theme="light"] / [data-theme="dark"]
 * set automatically by OsmosProvider.
 */

/* ==========================================================================
   Base Tokens (always available)
   ========================================================================== */

:root {
${baseLines.join("\n")}
}

/* ==========================================================================
   Semantic Tokens — Light mode (default)
   ========================================================================== */

:root,
[data-theme="light"] {
${lightLines.join("\n")}
}

/* ==========================================================================
   Semantic Tokens — Dark mode
   ========================================================================== */

[data-theme="dark"] {
${darkLines.join("\n")}
}
`;

fs.mkdirSync(path.dirname(OUT), { recursive: true });
fs.writeFileSync(OUT, css, "utf-8");

const lineCount = css.split("\n").length;
console.log(`✓ Generated ${OUT} (${lineCount} lines)`);
